I am trying to find out what is the fastest possible way to compute
M'M for M upper triangular. I have coded,

// [[Rcpp::export]]
SEXP Prod1(SEXP M_) {
  const mat M = as<mat>(M_) ;
  mat prodM = M ;
  prodM = trans(M) * M  ;
  return(wrap(prodM)) ;
}

// [[Rcpp::export]]
SEXP Prod2(SEXP M_) {
  const mat M = as<mat>(M_) ;
  mat prodM = M ;
  prodM = trimatu(M).t() * trimatu(M)  ;
  return(wrap(prodM)) ;
}


// [[Rcpp::export]]
SEXP Prod3(SEXP M_) {
  mat M = as<mat>(M_) ;
  int d = M.n_rows ;
  mat prodM = M ;
  double * vM = M.memptr() ;
  double * vprodM = prodM.memptr() ;
  const double one = 1 ;
  const double zero = 0 ;
  F77_CALL(dsyrk)("L","T",&d,&d,&one,vM,&d,&zero,vprodM,&d)  ;
  return(wrap(prodM)) ;
}

